// Parse output Groq → flat object yang bisa dipakai Build Decision
const groqResponse = $input.first().json;
const raw =
  groqResponse &&
  groqResponse.choices &&
  groqResponse.choices[0] &&
  groqResponse.choices[0].message
    ? groqResponse.choices[0].message.content
    : '';

let classification;
try {
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  classification = JSON.parse(cleaned);
} catch (e) {
  // Kalau Groq gagal / parse error → fallback aman, jangan ghosting
  classification = {
    intent: 'OTHER',
    confidence: 0.3,
    extracted: {},
    needs_human: true,
    reason: 'Classifier parse failed: ' + e.message
  };
}

const messageData = $('Parse WA Message').first().json;

return [
  {
    json: {
      ...messageData,
      intent: classification.intent || 'OTHER',
      confidence: typeof classification.confidence === 'number' ? classification.confidence : 0.5,
      extracted: classification.extracted || {},
      needs_human: !!classification.needs_human,
      classifierReason: classification.reason || ''
    }
  }
];

// =====================================================================
// BUILD DECISION — Single source of truth untuk balasan WA
// =====================================================================
// Aturan emas: replyText TIDAK PERNAH null. Semua pesan masuk DIBALAS.
// triggerEstimator/triggerProposal hanya true kalau benar-benar siap.
// =====================================================================

const j = $json;
const rawName = (j.clientName || 'kak').toString().trim();
const name = rawName.split(' ')[0] || 'kak';

const intent = j.intent || 'OTHER';
const confidence = typeof j.confidence === 'number' ? j.confidence : 0.5;
const ext = j.extracted || {};
const explicitNeedsHuman = !!j.needs_human;

// Low confidence dianggap butuh human supaya ga kasih balasan random
const needsHuman = explicitNeedsHuman || confidence < 0.45;

const pick = (arr) => arr[Math.floor(Math.random() * arr.length)];

let replyText = '';
let actionType = 'fallback';
let triggerEstimator = false;
let triggerProposal = false;

if (needsHuman) {
  replyText =
    'Halo ' + name +
    ', makasih udah hubungi Sudut Ruang. Pertanyaan kakak akan kita teruskan ke tim ya, mohon ditunggu sebentar.';
  actionType = 'human';
} else if (intent === 'GREETING') {
  replyText = pick([
    'Halo ' + name +
      ', makasih udah hubungi Sudut Ruang!\n\nKita bantu desain arsitektur & interior untuk rumah, cafe, kantor, villa, dan lainnya.\n\nCeritain dulu proyek yang lagi kakak rencanain.',
    'Hai ' + name +
      '! Selamat datang di Sudut Ruang.\n\nKita spesialis jasa desain arsitektur & interior. Mau bangun atau renovasi apa nih?',
    'Halo ' + name +
      '! Sudut Ruang di sini. Boleh share dulu kakak lagi rencanain proyek apa? (rumah/cafe/kantor/villa/lainnya)'
  ]);
  actionType = 'greeting';
} else if (intent === 'ASK_PRICE') {
  const hasType = !!ext.building_type;
  const hasArea = !!ext.area_sqm;
  if (hasType && hasArea) {
    replyText =
      'Oke ' + name + ', lagi kita hitungin estimasi buat ' +
      ext.building_type + ' ' + ext.area_sqm +
      'm². Tunggu sebentar ya, hasilnya kita kirim segera.';
    actionType = 'estimator';
    triggerEstimator = true;
  } else if (hasType) {
    replyText =
      'Oke, desain ' + ext.building_type +
      ' ya.\n\nBerapa luas areanya? (dalam m²)\n\nSama, kelas materialnya mau standar, menengah, atau premium?';
    actionType = 'collect_info';
  } else if (hasArea) {
    replyText =
      'Noted ' + ext.area_sqm +
      'm².\n\nIni untuk apa ya? Rumah, cafe, kantor, villa, atau yang lain?';
    actionType = 'collect_info';
  } else {
    replyText =
      'Boleh ceritain dulu proyeknya:\n1. Jenis bangunan (rumah/cafe/kantor/villa/renovasi)\n2. Luas area (m²)\n3. Kelas material (standar/menengah/premium)\n\nBiar kita bisa kasih estimasi yang akurat.';
    actionType = 'collect_info';
  }
} else if (intent === 'REQUEST_PROPOSAL') {
  replyText =
    'Siap ' + name +
    ', kita siapin proposal lengkapnya sekarang.\n\nProposal akan kita kirim ke WhatsApp ini dalam beberapa menit ya. Tunggu sebentar!';
  actionType = 'proposal';
  triggerProposal = true;
} else if (intent === 'FOLLOW_UP') {
  replyText =
    'Halo ' + name +
    ', makasih udah follow up. Tim kita lagi cek dan bakal update kakak segera ya.';
  actionType = 'human';
} else if (intent === 'GENERAL_QUESTION') {
  replyText =
    'Pertanyaan kakak udah kita catat. Tim kita akan jawab langsung biar lebih akurat ya, mohon ditunggu sebentar.';
  actionType = 'human';
} else {
  // OTHER — TETAP balas, jangan ghosting
  replyText =
    'Halo ' + name +
    ', makasih udah hubungi Sudut Ruang.\n\nBoleh ceritain lebih detail tentang proyeknya?\n• Jenis bangunan (rumah/cafe/kantor/villa)\n• Luas area\n• Lokasi';
  actionType = 'fallback';
}

return [
  {
    json: {
      ...j,
      replyText: replyText,
      actionType: actionType,
      triggerEstimator: triggerEstimator,
      triggerProposal: triggerProposal,
      finalNeedsHuman: needsHuman
    }
  }
];
